c = orderedcolors("gem");
cc = c(4:7,:);
colororder(cc);

t = 0:0.01:100;
rng(42)

noise = 0.05;
signal = [sin(t / 2).' sin(t / 4).' sin(t / 8).'];
u = signal;
%%
Q_ref = quaternion(signal, 'euler', 'ZYX', "frame");
[w x y z] = parts(Q_ref);
ref = [w x y z];

figure; %[output:5fa2097f]
plot(t, ref, '-') %[output:5fa2097f]
xlabel('Time (s)'); %[output:5fa2097f]
ylabel('Quaternion Components'); %[output:5fa2097f]
title('Reference position as Quaternion'); %[output:5fa2097f]
legend('w', 'x', 'y', 'z'); %[output:5fa2097f]
grid on; %[output:5fa2097f]
%%
%% Euler Angles to IMU Simulation
% signal columns: [pitch, roll, yaw] = [phi, theta, psi]
% Units: radians

t = t(:);       % column vector

phi   = u(:, 1);  % pitch
theta = u(:, 2);  % roll
psi   = u(:, 3);  % yaw

dt = mean(diff(t));

%% --- GYROSCOPE ---
% Angular velocity in body frame from Euler rate kinematics
% [p; q; r] = E(phi,theta) * [dphi/dt; dtheta/dt; dpsi/dt]

dphi   = gradient(phi,   dt);
dtheta = gradient(theta, dt);
dpsi   = gradient(psi,   dt);

% Euler rate to body rate transformation matrix E(phi, theta):
%   p =  dphi   - sin(theta)         .* dpsi
%   q =  cos(phi).*dtheta + sin(phi).*cos(theta) .* dpsi
%   r = -sin(phi).*dtheta + cos(phi).*cos(theta) .* dpsi

p = dphi   - sin(theta)                        .* dpsi;
q = cos(phi) .* dtheta + sin(phi) .* cos(theta) .* dpsi;
r = -sin(phi) .* dtheta + cos(phi) .* cos(theta) .* dpsi;

gyro = [p, q, r];  % rad/s  [N x 3]

%% --- ACCELEROMETER ---
% Specific force = R' * [0; 0; g]  (gravity rotated into body frame)
% ZYX rotation: R = Rz(psi) * Ry(theta) * Rx(phi)
% R' * g_world gives the gravity component sensed by the accelerometer

g = 9.81;  % m/s^2
accel = zeros(length(t), 3);

for i = 1:length(t)
    ph = phi(i); th = theta(i); ps = psi(i);

    % Full ZYX rotation matrix
    R = [cos(ps)*cos(th),  cos(ps)*sin(th)*sin(ph)-sin(ps)*cos(ph),  cos(ps)*sin(th)*cos(ph)+sin(ps)*sin(ph);
         sin(ps)*cos(th),  sin(ps)*sin(th)*sin(ph)+cos(ps)*cos(ph),  sin(ps)*sin(th)*cos(ph)-cos(ps)*sin(ph);
        -sin(th),           cos(th)*sin(ph),                           cos(th)*cos(ph)];

    % NED global reference frame
    g_world = [0; 0; g];

    % Body-frame accelerometer reading (no linear acceleration assumed)
    accel(i, :) = (R' * g_world)';
end

% accel columns: [ax, ay, az] in m/s^2

accel = accel + rand([size(accel, 1) 3]) * 0.2 - 0.1;
gyro = gyro + rand([size(gyro, 1) 3]) * 0.05 - 0.025;

writematrix(gyro, "data/sim_gyro_data.csv")
writematrix(accel, "data/sim_accel_data.csv")

%% --- PLOT ---
figure; %[output:00448e9f]

subplot(2,1,1); %[output:00448e9f]
plot(t, gyro(:,1), 'r', t, gyro(:,2), 'g', t, gyro(:,3), 'b', 'LineWidth', 1.4); %[output:00448e9f]
xlabel('Time (s)'); ylabel('rad/s'); %[output:00448e9f]
title('Simulated Gyroscope Output (Body Frame)'); %[output:00448e9f]
legend('p (roll rate)', 'q (pitch rate)', 'r (yaw rate)'); %[output:00448e9f]
grid on; %[output:00448e9f]

subplot(2,1,2); %[output:00448e9f]
plot(t, accel(:,1), 'r', t, accel(:,2), 'g', t, accel(:,3), 'b', 'LineWidth', 1.4); %[output:00448e9f]
xlabel('Time (s)'); ylabel('m/s^2'); %[output:00448e9f]
title('Simulated Accelerometer Output (Body Frame)'); %[output:00448e9f]
legend('ax', 'ay', 'az'); %[output:00448e9f]
grid on; %[output:00448e9f]

% A bit closer look
figure; %[output:55b5be7c]
subplot(2,1,1); %[output:55b5be7c]
plot(t, gyro(:,1), 'r', t, gyro(:,2), 'g', t, gyro(:,3), 'b', 'LineWidth', 1.4); %[output:55b5be7c]
xlabel('Time (s)'); ylabel('rad/s'); %[output:55b5be7c]
title('Simulated Gyroscope Output (Body Frame)'); %[output:55b5be7c]
legend('p (roll rate)', 'q (pitch rate)', 'r (yaw rate)'); %[output:55b5be7c]
grid on; %[output:55b5be7c]
xlim([40 60]) %[output:55b5be7c]

subplot(2,1,2); %[output:55b5be7c]
plot(t, accel(:,1), 'r', t, accel(:,2), 'g', t, accel(:,3), 'b', 'LineWidth', 1.4); %[output:55b5be7c]
xlabel('Time (s)'); ylabel('m/s^2'); %[output:55b5be7c]
title('Simulated Accelerometer Output (Body Frame)'); %[output:55b5be7c]
legend('ax', 'ay', 'az'); %[output:55b5be7c]
grid on; %[output:55b5be7c]
xlim([40 60]) %[output:55b5be7c]
%%
result = readmatrix("data/ahrs_nc_output.csv");

figure; %[output:6ac05c9c]
plot(t, result, t, ref, '--') %[output:6ac05c9c]
xlabel('Time (s)'); %[output:6ac05c9c]
ylabel('Quaternion Components'); %[output:6ac05c9c]
title('Comparison of output of NC AQUA Filter'); %[output:6ac05c9c]
legend('w', 'x', 'y', 'z', 'Reference', 'Location', 'Best'); %[output:6ac05c9c]
grid on; %[output:6ac05c9c]
%%
result = readmatrix("data/ahrs_ekf_output.csv");

figure; %[output:608698e0]
plot(t, result, t, ref, '--') %[output:608698e0]
xlabel('Time (s)'); %[output:608698e0]
ylabel('Quaternion Components'); %[output:608698e0]
title('Comparison of output of EKF Filter'); %[output:608698e0]
legend('w', 'x', 'y', 'z', 'Reference', 'Location', 'Best'); %[output:608698e0]
grid on; %[output:608698e0]

